from llama_stack_client import LlamaStackAgent
from vex_sdk import verify

agent = LlamaStackAgent()

@verify(check='memory_retrieval_hallucination')
def detect_memory_hallucination(query, retrieved_docs):
    from sentence_transformers import SentenceTransformer, util
    model = SentenceTransformer('all-MiniLM-L6-v2')

    query_emb = model.encode(query)
    doc_embs = model.encode([doc['content'] for doc in retrieved_docs])

    similarities = util.cos_sim(query_emb, doc_embs)[0]
    avg_similarity = float(similarities.mean())

    if avg_similarity < 0.3:
        return {
            'pass': False,
            'score': avg_similarity,
            'failure': f'Low semantic similarity: {avg_similarity:.3f}',
            'retrieved_doc_ids': [doc['doc_id'] for doc in retrieved_docs]
        }
    return {'pass': True, 'score': avg_similarity}

from llama_stack_client import MemoryBank

@verify(check='memory_bank_bloat')
def detect_memory_bloat(memory_bank: MemoryBank):
    stats = memory_bank.get_stats()
    total_entries = stats['total_entries']
    active_entries = stats['active_entries']
    growth_rate = stats.get('growth_rate', 0)

    bloat_ratio = (total_entries - active_entries) / max(total_entries, 1)

    if bloat_ratio > 0.4 or growth_rate > 10:
        return {
            'pass': False,
            'bloat_ratio': bloat_ratio,
            'growth_rate': growth_rate,
            'total_entries': total_entries,
            'failure': f'Bloat ratio {bloat_ratio:.2f}, growth {growth_rate}',
        }
    return {'pass': True}

@verify(check='safety_false_positive')
def detect_safety_false_positives(safety_events):
    benign_blocked = 0
    total_blocked = 0

    for event in safety_events:
        if event['blocked'] and event['confidence'] < 0.3:
            benign_blocked += 1
        if event['blocked']:
            total_blocked += 1

    false_positive_rate = benign_blocked / max(total_blocked, 1)

    if false_positive_rate > 0.25:
        return {
            'pass': False,
            'false_positive_rate': false_positive_rate,
            'benign_blocked': benign_blocked,
            'total_blocked': total_blocked
        }
    return {'pass': True}

