from pydantic import BaseModel, ValidationError
from llama_stack_client import MemoryBank

class ToolResponse(BaseModel):
    tool_name: str
    args: dict
    result: dict
    timestamp: str

@verify(check='schema_validated_memory')
def safe_memory_write(memory_bank: MemoryBank, tool_output: dict):
    try:
        validated = ToolResponse(**tool_output)
        memory_bank.write(
            doc_id=f"tool_{validated.timestamp}",
            content=str(validated),
            metadata={'tool_name': validated.tool_name}
        )
        return {'pass': True, 'doc_id': validated.timestamp}
    except ValidationError as e:
        return {
            'pass': False,
            'error': str(e),
            'raw_output': tool_output
        }

from llama_stack_client import LlamaStackAgent

BENIGN_PATTERNS = [
    'retrieved memory',
    'tool response',
    'conversation history',
    'document chunk'
]

class SafeMemoryRetriever:
    def __init__(self, agent: LlamaStackAgent):
        self.agent = agent

    def retrieve_with_safety_override(self, query: str, max_results: int = 5):
        results = self.agent.memory_bank.retrieve(query, limit=max_results)

        filtered = []
        for doc in results:
            # Check if safety-blocked but matches benign pattern
            if doc.get('safety_blocked') and any(pattern in doc['content'] for pattern in BENIGN_PATTERNS):
                doc['safety_overridden'] = True
                filtered.append(doc)
            elif not doc.get('safety_blocked'):
                filtered.append(doc)

        return filtered
